// input.js - Обработка ввода
const movement = {
    up: false,
    down: false,
    left: false,
    right: false
};

export function initInput() {
    document.addEventListener('keydown', (event) => {
        switch (event.code) {
            case 'KeyA':
            case 'ArrowLeft':
                movement.left = true;
                break;
            case 'KeyW':
            case 'ArrowUp':
                movement.up = true;
                break;
            case 'KeyD':
            case 'ArrowRight':
                movement.right = true;
                break;
            case 'KeyS':
            case 'ArrowDown':
                movement.down = true;
                break;
        }
    });

    document.addEventListener('keyup', (event) => {
        switch (event.code) {
            case 'KeyA':
            case 'ArrowLeft':
                movement.left = false;
                break;
            case 'KeyW':
            case 'ArrowUp':
                movement.up = false;
                break;
            case 'KeyD':
            case 'ArrowRight':
                movement.right = false;
                break;
            case 'KeyS':
            case 'ArrowDown':
                movement.down = false;
                break;
        }
    });
}

export function getMovement() {
    return movement;
}

// renderer.js - Отрисовка игры
export function drawGame(ctx, players, localId, width, height) {
    ctx.clearRect(0, 0, width, height);

    // Сетка (фон)
    drawGrid(ctx, width, height);

    // Отрисовка игроков
    for (const id in players) {
        const player = players[id];
        const isLocal = id === localId;
        drawPlayer(ctx, player, isLocal);
    }
}

function drawGrid(ctx, w, h) {
    ctx.strokeStyle = 'rgba(0,0,0,0.05)';
    ctx.lineWidth = 1;
    const gridSize = 50;

    for (let x = 0; x <= w; x += gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, h);
        ctx.stroke();
    }
    for (let y = 0; y <= h; y += gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(w, y);
        ctx.stroke();
    }
}

function drawPlayer(ctx, player, isLocal) {
    // Тень
    ctx.beginPath();
    ctx.arc(player.x, player.y + 5, 20, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(0,0,0,0.2)';
    ctx.fill();

    // Тело
    ctx.beginPath();
    ctx.arc(player.x, player.y, 20, 0, Math.PI * 2);
    ctx.fillStyle = player.color;
    ctx.fill();

    // Обводка
    ctx.lineWidth = isLocal ? 3 : 2;
    ctx.strokeStyle = isLocal ? '#fff' : '#3e2723';
    ctx.stroke();

    // Глаза
    ctx.fillStyle = 'white';
    ctx.beginPath();
    ctx.arc(player.x - 6, player.y - 4, 6, 0, Math.PI * 2);
    ctx.arc(player.x + 6, player.y - 4, 6, 0, Math.PI * 2);
    ctx.fill();

    ctx.fillStyle = 'black';
    ctx.beginPath();
    ctx.arc(player.x - 6, player.y - 4, 2, 0, Math.PI * 2);
    ctx.arc(player.x + 6, player.y - 4, 2, 0, Math.PI * 2);
    ctx.fill();

    // Никнейм
    ctx.fillStyle = isLocal ? '#ffff00' : 'white';
    ctx.font = 'bold 14px Verdana';
    ctx.textAlign = 'center';
    ctx.strokeStyle = 'black';
    ctx.lineWidth = 3;
    ctx.strokeText(player.nickname, player.x, player.y - 30);
    ctx.fillText(player.nickname, player.x, player.y - 30);
}

// ui.js - Управление DOM элементами
const screens = {
    start: document.getElementById('start-screen'),
    lobby: document.getElementById('lobby-screen'),
    error: document.getElementById('error-screen')
};

const elements = {
    canvas: document.querySelector('canvas'),
    roomList: document.getElementById('room-list'),
    onlineCounter: document.getElementById('online-counter'),
    onlineText: document.getElementById('online-text'), // Текст внутри счетчика
    nicknameInput: document.getElementById('globalNicknameInput'),
    createRoomInput: document.getElementById('createRoomInput'),
    connectionLoader: document.getElementById('connection-loader'),
    connectionStatus: document.getElementById('connection-status'),
    errorMsg: document.getElementById('error-msg')
};

export function getNickname() {
    return elements.nicknameInput.value.trim() || 'Player';
}

export function getCreateRoomName() {
    return elements.createRoomInput.value.trim();
}

export function showScreen(screenName) {
    // Скрываем все
    Object.values(screens).forEach(el => {
        if(el) el.classList.remove('active');
    });
    elements.canvas.style.display = 'none';

    // Показываем нужный
    if (screenName === 'game') {
        elements.canvas.style.display = 'block';
    } else if (screens[screenName]) {
        screens[screenName].classList.add('active');
    }
}

export function showError(msg) {
    elements.errorMsg.textContent = msg;
    screens.error.style.display = 'flex';
}

export function hideError() {
    screens.error.style.display = 'none';
}

export function updateOnlineCount(count) {
    elements.onlineCounter.style.display = 'block';
    // Обновляем текст внутри div
    elements.onlineCounter.textContent = `Online: ${count}`;
}

export function updateRoomList(rooms, onJoin) {
    elements.roomList.innerHTML = '';
    if (rooms.length === 0) {
        elements.roomList.innerHTML = '<div style="padding:10px; text-align:center; color:#888;">Нет активных комнат</div>';
        return;
    }

    rooms.forEach(room => {
        const div = document.createElement('div');
        div.className = 'room-item';
        div.innerHTML = `
            <span>${room.name}</span>
            <span class="room-count">${room.players} чел.</span>
        `;
        div.onclick = () => onJoin(room.id);
        elements.roomList.appendChild(div);
    });
}

export function setConnectionStatus(text, isLoading) {
    if (elements.connectionStatus) elements.connectionStatus.textContent = text;
    if (elements.connectionLoader) elements.connectionLoader.style.display = isLoading ? 'block' : 'none';
}

// main.js - Точка входа
import { initInput, getMovement } from './input.js';
import { drawGame } from './renderer.js';
import * as UI from './ui.js';

const CANVAS_WIDTH = 800;
const CANVAS_HEIGHT = 600;

// Инициализация Canvas
const canvas = document.querySelector('canvas');
canvas.width = CANVAS_WIDTH;
canvas.height = CANVAS_HEIGHT;
const ctx = canvas.getContext('2d');

let socket = null;
let isOfflineMode = false;

// Игровое состояние
let players = {};
let myId = null;

// Инициализация управления
initInput();

// --- ГЛОБАЛЬНЫЕ ФУНКЦИИ (для вызова из HTML кнопок) ---
window.selectOnline = function() {
    isOfflineMode = false;
    UI.setConnectionStatus("Подключение к серверу...", true);

    // Подключаемся к сокету
    socket = io();

    socket.on('connect', () => {
        UI.setConnectionStatus("", false);
        UI.showScreen('lobby');
        myId = socket.id;
    });

    socket.on('connect_error', () => {
        UI.setConnectionStatus("Ошибка подключения!", false);
    });

    socket.on('onlineCount', (count) => {
        UI.updateOnlineCount(count);
    });

    socket.on('roomList', (rooms) => {
        UI.updateRoomList(rooms, (roomId) => {
            socket.emit('joinRoom', roomId, UI.getNickname());
        });
    });

    socket.on('gameStart', (initialPlayers) => {
        players = initialPlayers;
        UI.showScreen('game');
        startGameLoop();
    });

    socket.on('state', (serverPlayers) => {
        players = serverPlayers;
    });

    socket.on('error', (msg) => {
        UI.showError(msg);
    });
};

window.selectOffline = function() {
    isOfflineMode = true;
    myId = 'local_player';

    // Создаем локального игрока
    players = {
        [myId]: {
            x: CANVAS_WIDTH / 2,
            y: CANVAS_HEIGHT / 2,
            color: 'hsl(200, 70%, 50%)',
            id: myId,
            nickname: UI.getNickname()
        },
        'bot_1': {
            x: 100, y: 100, color: 'red', id: 'bot_1', nickname: 'Bot'
        }
    };

    UI.showScreen('game');
    startGameLoop();
};

window.createRoom = function() {
    if (socket) {
        socket.emit('createRoom', UI.getCreateRoomName(), UI.getNickname());
    }
};

window.closeError = function() {
    UI.hideError();
    if (!socket || !socket.connected) {
        UI.showScreen('start');
    } else {
        UI.showScreen('lobby');
    }
};

window.backToMenu = function() {
    UI.showScreen('start');
    if (socket) {
        socket.disconnect();
        socket = null;
    }
};

// --- ИГРОВОЙ ЦИКЛ ---
function startGameLoop() {
    function loop() {
        // Если игра идет (холст видим)
        if (canvas.style.display === 'block') {
            const move = getMovement();

            if (isOfflineMode) {
                updateOfflineLogic(move);
            } else {
                // Отправляем движение на сервер
                if (socket) {
                    socket.emit('movement', move);
                }
            }

            drawGame(ctx, players, myId, CANVAS_WIDTH, CANVAS_HEIGHT);
            requestAnimationFrame(loop);
        }
    }
    loop();
}

function updateOfflineLogic(move) {
    const p = players[myId];
    const speed = 5;

    if (move.left) p.x -= speed;
    if (move.right) p.x += speed;
    if (move.up) p.y -= speed;
    if (move.down) p.y += speed;

    // Границы
    p.x = Math.max(20, Math.min(CANVAS_WIDTH - 20, p.x));
    p.y = Math.max(20, Math.min(CANVAS_HEIGHT - 20, p.y));
}

