// renderer.js - Отрисовка игры
(function() {
    function drawGame(ctx, players, localId, width, height) {
        ctx.clearRect(0, 0, width, height);

        // Сетка (фон)
        drawGrid(ctx, width, height);

        // Отрисовка игроков
